// ---- Coroutines in ViewModel ----

// ---- Data models ----
data class Post(
    val id: Int,
    val title: String,
    val body: String
)

data class User(
    val id: Int,
    val name: String,
    val email: String
)

// ---- Repository pattern ----
class Repository {
    // Simulate network call
    suspend fun getPosts(): List<Post> {
        delay(1500)
        return listOf(
            Post(1, "First Post", "This is the first post"),
            Post(2, "Second Post", "This is the second post"),
            Post(3, "Third Post", "This is the third post")
        )
    }

    suspend fun getUser(id: Int): User {
        delay(1000)
        return User(id, "User $id", "user$id@example.com")
    }

    suspend fun savePost(post: Post) {
        delay(800)
        // Simulate saving
    }
}

// ---- ViewModel with coroutines ----
class CoroutineViewModel(
    private val repository: Repository = Repository()
) : ViewModel() {
    // ---- UI State ----
    data class UiState(
        val posts: List<Post> = emptyList(),
        val user: User? = null,
        val isLoading: Boolean = false,
        val error: String? = null
    )

    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    // ---- Load data with coroutines ----
    fun loadData() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }

            try {
                // Load posts and user in parallel
                val postsDeferred = async { repository.getPosts() }
                val userDeferred = async { repository.getUser(1) }

                val posts = postsDeferred.await()
                val user = userDeferred.await()

                _uiState.update { it.copy(
                    posts = posts,
                    user = user,
                    isLoading = false
                )}
            } catch (e: Exception) {
                _uiState.update { it.copy(
                    error = e.message ?: "Unknown error",
                    isLoading = false
                )}
            }
        }
    }

    // ---- Save data with coroutines ----
    fun savePost(title: String, body: String) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }

            try {
                val newPost = Post(
                    id = (_uiState.value.posts.maxOfOrNull { it.id } ?: 0) + 1,
                    title = title,
                    body = body
                )

                repository.savePost(newPost)

                _uiState.update { it.copy(
                    posts = it.posts + newPost,
                    isLoading = false
                )}
            } catch (e: Exception) {
                _uiState.update { it.copy(
                    error = e.message ?: "Failed to save",
                    isLoading = false
                )}
            }
        }
    }

    // ---- Refresh data ----
    fun refresh() {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true) }

            try {
                val posts = repository.getPosts()
                _uiState.update { it.copy(
                    posts = posts,
                    isLoading = false
                )}
            } catch (e: Exception) {
                _uiState.update { it.copy(
                    error = e.message ?: "Refresh failed",
                    isLoading = false
                )}
            }
        }
    }

    // ---- Clear error ----
    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }
}

// ---- UI Screen ----
@Composable
fun CoroutineScreen() {
    val viewModel: CoroutineViewModel = viewModel()
    val uiState by viewModel.uiState.collectAsState()

    var title by remember { mutableStateOf("") }
    var body by remember { mutableStateOf("") }

    Scaffold(
        topBar = {
            TopAppBar {
                Text("Coroutines Demo")
            }
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // ---- Loading ----
            if (uiState.isLoading) {
                Box(
                    modifier = Modifier.fillMaxWidth().height(50.dp),
                    contentAlignment = Alignment.Center
                ) {
                    CircularProgressIndicator()
                }
            }

            // ---- Error ----
            if (uiState.error != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer
                    )
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = uiState.error ?: "",
                            color = MaterialTheme.colorScheme.onErrorContainer
                        )
                        Button(
                            onClick = { viewModel.clearError() }
                        ) {
                            Text("Dismiss")
                        }
                    }
                }
            }

            // ---- User info ----
            if (uiState.user != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Text(
                            text = "User: ${uiState.user?.name}",
                            style = MaterialTheme.typography.titleMedium
                        )
                        Text(
                            text = uiState.user?.email ?: ""
                        )
                    }
                }
            }

            // ---- Add post form ----
            OutlinedTextField(
                value = title,
                onValueChange = { title = it },
                label = { Text("Title") },
                modifier = Modifier.fillMaxWidth()
            )

            OutlinedTextField(
                value = body,
                onValueChange = { body = it },
                label = { Text("Body") },
                modifier = Modifier.fillMaxWidth()
            )

            Button(
                onClick = {
                    if (title.isNotBlank() && body.isNotBlank()) {
                        viewModel.savePost(title, body)
                        title = ""
                        body = ""
                    }
                },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Add Post")
            }

            // ---- Posts list ----
            LazyColumn(
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(uiState.posts) { post ->
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        elevation = CardDefaults.cardElevation(2.dp)
                    ) {
                        Column(
                            modifier = Modifier.padding(16.dp)
                        ) {
                            Text(
                                text = post.title,
                                style = MaterialTheme.typography.titleMedium
                            )
                            Text(
                                text = post.body,
                                style = MaterialTheme.typography.bodyMedium
                            )
                        }
                    }
                }
            }

            // ---- Load button ----
            Button(
                onClick = { viewModel.loadData() },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Load Data")
            }

            Button(
                onClick = { viewModel.refresh() },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Refresh")
            }
        }
    }
}

